const workflows = ($('Get All n8n Workflows').first().json.data || []);
const executions = ($('Get Failed Executions 24h').first().json.data || []);
const emails = $input.all().map(e => e.json);

const now = new Date();
const twentyFourHoursAgo = now.getTime() - 24 * 60 * 60 * 1000;
const recentFailures = executions.filter(e => new Date(e.startedAt).getTime() > twentyFourHoursAgo);

const active = workflows.filter(w => w.active);
const inactive = workflows.filter(w => !w.active);

const failuresByWf = {};
recentFailures.forEach(e => {
  const name = workflows.find(w => w.id === e.workflowId)?.name || e.workflowId;
  if (!failuresByWf[name]) failuresByWf[name] = 0;
  failuresByWf[name]++;
});

const failureSummary = Object.entries(failuresByWf)
  .sort((a,b) => b[1]-a[1])
  .map(([name, count]) => `${name}: ${count} error(s)`)
  .join(', ') || 'None — all systems nominal';

// Outlook emails: from is { emailAddress: { name, address } }
const emailSummary = emails.slice(0, 7).map((e, i) => {
  const subj = (e.subject || '(no subject)').substring(0, 60);
  const sender = (e.from && e.from.emailAddress)
    ? (e.from.emailAddress.name || e.from.emailAddress.address || 'unknown').substring(0, 40)
    : 'unknown';
  return `${i+1}. "${subj}" — ${sender}`;
}).join('\n') || 'Inbox is clear';

return [{ json: {
  date: now.toLocaleDateString('en-GB', {weekday:'long', year:'numeric', month:'long', day:'numeric'}),
  time: now.toLocaleTimeString('en-GB', {hour:'2-digit', minute:'2-digit', timeZone:'Europe/London'}),
  totalWorkflows: workflows.length,
  activeCount: active.length,
  inactiveCount: inactive.length,
  activeWorkflows: active.map(w => w.name).join(', ') || 'None',
  inactiveWorkflows: inactive.map(w => w.name).join(', ') || 'None',
  failuresLast24h: recentFailures.length,
  failureSummary,
  unreadEmails: emails.length,
  emailSummary
}}];

const d = $input.first().json;
const healthEmoji = d.failuresLast24h === 0 ? '🟢' : d.failuresLast24h < 5 ? '🟡' : '🔴';
const healthLabel = d.failuresLast24h === 0 ? 'ALL SYSTEMS NOMINAL' : `${d.failuresLast24h} FAILURES DETECTED`;

const prompt = `You are the AI Chief of Staff for a high-tech digital super-agent operation. Generate a concise morning briefing for a Telegram message (plain text, no HTML). Use Telegram Markdown: *bold*, _italic_, \`code\`. Keep under 3500 characters.

DATA INPUT:
- Date: ${d.date} | Time: ${d.time} GMT
- Total n8n Workflows: ${d.totalWorkflows} (${d.activeCount} active, ${d.inactiveCount} inactive)
- Active Workflows: ${d.activeWorkflows}
- Inactive Workflows (need attention): ${d.inactiveWorkflows}
- Failures in last 24h: ${d.failuresLast24h} — ${d.failureSummary}
- Unread Emails (Outlook): ${d.unreadEmails}
- Top Inbox Items:\n${d.emailSummary}

Structure the Telegram message with these sections:
1. Header line: 🧑🏾 *Chief of Staff — Morning Briefing* and date/time
2. ${healthEmoji} *System Health:* ${healthLabel} — brief one-line summary
3. 📊 *Workflows:* active count, inactive list (if any)
4. 📬 *Outlook Inbox:* unread count + top email subjects
5. ⚡ *Action Items:* 3-5 bullet points based on failures and inactive workflows

Return ONLY the Telegram message text, no extra commentary.`;

return [{json: {prompt}}];

const raw = $input.first().json.candidates[0].content.parts[0].text;
const text = raw.replace(/^```[a-z]*\n?/i, '').replace(/\n?```$/i, '').trim();
return [{ json: { telegram_text: text } }];

const executions = ($input.first().json.data || []);
const windowMs = 20 * 60 * 1000;
const cutoff = Date.now() - windowMs;

const recent = executions.filter(e => new Date(e.startedAt).getTime() > cutoff);

const byWorkflow = {};
recent.forEach(e => {
  if (!e.workflowId) return;
  if (!byWorkflow[e.workflowId]) byWorkflow[e.workflowId] = {workflowId: e.workflowId, count: 0};
  byWorkflow[e.workflowId].count++;
});

const failures = Object.values(byWorkflow);
const critical = failures.filter(f => f.count >= 2);
const failingIds = failures.map(f => f.workflowId).filter(Boolean);

return [{ json: {
  failureCount: failures.length,
  criticalCount: critical.length,
  failingIds,
  criticalWorkflows: critical.map(f => `WorkflowID ${f.workflowId} (${f.count} errors)`).join(', ') || 'None',
  allFailures: failures.map(f => `${f.workflowId}: ${f.count}`).join(', '),
  timestamp: new Date().toISOString(),
  windowMinutes: 20
}}];

const h = $input.first().json;
const prompt = `URGENT: System alert for the Super-Agent n8n automation platform.

In the last ${h.windowMinutes} minutes:
- Failing workflows: ${h.failureCount}
- Critical (2+ errors): ${h.criticalWorkflows}
- All failures: ${h.allFailures}
- Failing workflow IDs: ${h.failingIds.join(', ')}

Provide:
1. A concise 2-sentence diagnosis
2. Immediate recommended action (1 sentence)
3. Severity level: LOW / MEDIUM / HIGH / CRITICAL
4. Whether auto-restart is appropriate (yes/no)

Return JSON: {"diagnosis": "...", "action": "...", "severity": "...", "auto_restart": true/false, "subject_line": "alert email subject max 60 chars"}`;
return [{json: {prompt, failureCount: h.failureCount, criticalWorkflows: h.criticalWorkflows, failingIds: h.failingIds}}];

const raw = $input.first().json.candidates[0].content.parts[0].text;
let parsed;
try {
  const extracted = (raw.match(/\{[\s\S]*\}/) || [raw])[0];
  parsed = JSON.parse(extracted);
} catch(e) {
  parsed = {diagnosis: raw, action: 'Check n8n execution logs', severity: 'MEDIUM', auto_restart: false, subject_line: 'System Alert: Workflow Failures Detected'};
}

const health = $('Evaluate System Health').first().json;
const severityEmoji = parsed.severity === 'CRITICAL' ? '🚨' : parsed.severity === 'HIGH' ? '🔴' : parsed.severity === 'LOW' ? '🟡' : '🟠';
const autoHealMsg = parsed.auto_restart ? '\n🔧 *Auto-Heal:* Restarting failing workflow(s) now.' : '';

const telegram_text = `${severityEmoji} *[${parsed.severity}] Chief of Staff — System Alert*
_${new Date().toLocaleString('en-GB')}_

*Failures:* ${health.failureCount} workflow(s) in last ${health.windowMinutes} min
*Critical:* ${health.criticalWorkflows}${autoHealMsg}

*Diagnosis:* ${parsed.diagnosis}
*Action:* ${parsed.action}

_Commands: POST /webhook/chief-of-staff_`;

return [{json: { telegram_text, autoRestart: parsed.auto_restart }}];

const raw = $input.first().json.candidates[0].content.parts[0].text;
let parsed;
try {
  const extracted = (raw.match(/\{[\s\S]*\}/) || [raw])[0];
  parsed = JSON.parse(extracted);
} catch(e) {
  parsed = {intent: 'general', query: $('Build Command Prompt').first().json.original_command};
}
const valid = ['status','activate','deactivate','restart','history','dispatch','brief','general'];
if (!valid.includes(parsed.intent)) parsed.intent = 'general';
return [{json: parsed}];

const workflows = ($input.first().json.data || []);
const active = workflows.filter(w => w.active);
const inactive = workflows.filter(w => !w.active);

const activeList = active.map(w => `✅ ${w.name}`).join('\n');
const inactiveList = inactive.map(w => `⏸️  ${w.name}`).join('\n');

return [{ json: {
  success: true,
  response: `🧑🏾 CHIEF OF STAFF — SYSTEM STATUS\n\n📊 Total: ${workflows.length} workflows\n\n🟢 ACTIVE (${active.length}):\n${activeList}\n\n🔴 INACTIVE (${inactive.length}):\n${inactiveList}\n\n💡 Commands: activate [name] | deactivate [name] | restart [name] | history | dispatch to [agent]: [command]`,
  timestamp: new Date().toISOString(),
  active_count: active.length,
  inactive_count: inactive.length
}}];

const workflows = ($input.first().json.data || []);
const intent = $('Parse Command Result').first().json;
const targetName = ((intent.workflow_name || intent.query || '')).toLowerCase().trim();
const isActivate = intent.intent === 'activate';

if (!targetName) {
  return [{json: {error: true, message: 'No workflow name specified. Usage: {"command": "activate Crypto Specialist"}'}}];
}

const match = workflows.find(w => w.name.toLowerCase().includes(targetName));
if (!match) {
  const available = workflows.map(w => w.name).join(', ');
  return [{json: {error: true, message: `Workflow "${targetName}" not found. Available: ${available}`}}];
}

return [{json: { error: false, workflow_id: match.id, workflow_name: match.name, new_active: isActivate, action: isActivate ? 'activated' : 'deactivated' }}];

const workflows = ($input.first().json.data || []);
const intent = $('Parse Command Result').first().json;
const targetName = ((intent.workflow_name || intent.query || '')).toLowerCase().trim();

if (!targetName) {
  return [{json: {error: true, message: 'No workflow name specified. Usage: {"command": "restart Crypto Specialist"}'}}];
}

const match = workflows.find(w => w.name.toLowerCase().includes(targetName));
if (!match) {
  const available = workflows.map(w => w.name).join(', ');
  return [{json: {error: true, message: `Workflow "${targetName}" not found. Available: ${available}`}}];
}

return [{json: { error: false, workflow_id: match.id, workflow_name: match.name, was_active: match.active }}];

const executions = ($('Get Error History').first().json.data || []).slice(0, 15);
const workflows = ($input.first().json.data || []);

const wfMap = {};
workflows.forEach(w => { wfMap[w.id] = w.name; });

const failuresByWf = {};
executions.forEach(e => {
  const name = wfMap[e.workflowId] || `ID:${e.workflowId}`;
  if (!failuresByWf[name]) failuresByWf[name] = 0;
  failuresByWf[name]++;
});

const sorted = Object.entries(failuresByWf).sort((a,b) => b[1]-a[1]);
const topFailer = sorted[0]?.[0] || 'None';
const topCount = sorted[0]?.[1] || 0;

const recentList = executions.slice(0, 12).map((e, i) => {
  const name = wfMap[e.workflowId] || e.workflowId;
  const dt = new Date(e.startedAt);
  const time = dt.toLocaleTimeString('en-GB', {hour:'2-digit', minute:'2-digit'});
  const date = dt.toLocaleDateString('en-GB', {day:'numeric', month:'short'});
  return `${i+1}. [${date} ${time}] ${name}`;
}).join('\n');

const leaderboard = sorted.slice(0,5).map(([name,cnt]) => `  ${name}: ${cnt} failure(s)`).join('\n');

return [{json: {
  success: true,
  response: `🧑🏾 CHIEF OF STAFF — ERROR HISTORY\n\n📋 Last ${executions.length} failed executions:\n\n${recentList}\n\n🏴 Failure Leaderboard (most problematic):\n${leaderboard}\n\n💡 Remediation:\n• To restart a workflow: {"command": "restart [name]"}\n• To check live status: {"command": "status"}\n• For full alert: {"command": "dispatch to gmail secretary: check unread"}`,
  timestamp: new Date().toISOString()
}}];

const intent = $input.first().json;
const N8N_BASE = 'https://outstanding-blessing-production-1d4b.up.railway.app';

const webhookMap = [
  {keys: ['gmail secretary', 'gmail manager', 'gmail'], path: '/webhook/gmail-secretary'},
  {keys: ['outlook secretary', 'outlook', 'microsoft'], path: '/webhook/secretary'},
  {keys: ['chief of staff', 'chief', 'cos'], path: '/webhook/chief-of-staff'}
];

const target = (intent.target || intent.query || '').toLowerCase();
let path = '/webhook/gmail-secretary';
for (const mapping of webhookMap) {
  if (mapping.keys.some(k => target.includes(k))) { path = mapping.path; break; }
}

const subCommand = intent.sub_command || intent.query || 'status';

return [{json: {
  webhook_url: N8N_BASE + path,
  sub_command: subCommand,
  target: intent.target || 'gmail secretary',
  path
}}];

const result = $input.first().json;
const intent = $('Parse Command Result').first().json;
const dispatchMeta = $('Build Dispatch Call').first().json;

let responseText;
if (result.code && result.code >= 400) {
  responseText = `⚠️ The sub-agent at ${dispatchMeta.path} returned an error: ${result.message || JSON.stringify(result)}`;
} else if (typeof result.response === 'string') {
  responseText = result.response;
} else {
  responseText = JSON.stringify(result, null, 2);
}

return [{json: {
  success: true,
  response: `🧑🏾 CHIEF OF STAFF — DISPATCH RESULT\n\n📡 Routed to: ${dispatchMeta.target}\n💬 Command: "${dispatchMeta.sub_command}"\n\n📩 Sub-agent response:\n${responseText}`,
  timestamp: new Date().toISOString()
}}];

const workflows = ($input.first().json.data || []);
const active = workflows.filter(w => w.active);
const inactive = workflows.filter(w => !w.active);
const now = new Date();

const brief = `🧑🏾 CHIEF OF STAFF — INSTANT BRIEFING
📅 ${now.toLocaleDateString('en-GB', {weekday:'long', day:'numeric', month:'long', year:'numeric'})} | ${now.toLocaleTimeString('en-GB')}

📊 SYSTEM OVERVIEW
• ${workflows.length} total workflows registered
• ${active.length} currently active
• ${inactive.length} dormant

🟢 ACTIVE WORKFORCE:
${active.map(w => `  → ${w.name}`).join('
')}

⏸️ DORMANT (activate on demand):
${inactive.map(w => `  → ${w.name}`).join('
')}

💡 FULL COMMAND MENU:
• status — Full health report
• activate [name] — Start a workflow
• deactivate [name] — Pause a workflow
• restart [name] — Hard restart a workflow
• history — View recent system errors
• dispatch to [gmail|outlook] secretary: [command] — Route to a sub-agent
• [any question] — Ask me anything

— 🧑🏾 Chief of Staff AI, ${now.toISOString()}`;

return [{ json: {success: true, response: brief, timestamp: now.toISOString(), active_count: active.length, inactive_count: inactive.length}}];

const workflows = ($input.first().json.data || []);
const intent = $('Parse Command Result').first().json;
const query = intent.query || intent.workflow_name || 'hello';
const active = workflows.filter(w => w.active).map(w => w.name);
const inactive = workflows.filter(w => !w.active).map(w => w.name);

const prompt = `You are the Chief of Staff AI (🧑🏾) for a digital super-agent automation system. You are intelligent, concise, and actionable.

LIVE SYSTEM STATE RIGHT NOW:
- Active workflows (${active.length}): ${active.join(', ')}
- Dormant workflows (${inactive.length}): ${inactive.join(', ')}

YOUR FULL CAPABILITIES:
- status: full system health report
- brief: instant intelligence briefing
- activate [name] / deactivate [name]: control any workflow
- restart [name]: hard restart a workflow
- history: analyse recent system errors
- dispatch to gmail secretary: [command] — route commands to Gmail Secretary
- dispatch to outlook secretary: [command] — route commands to Outlook Secretary
- [any question]: answer anything about the system

USER QUERY: "${query}"

Respond in 3-5 sentences. Be specific — reference actual workflow names and states from the live data above. Give actionable advice.`;

return [{json: {prompt}}];
